if (!defined('ABSPATH')) exit;

function mpd_get_int_from_get($key) {
	if (!isset($_GET[$key])) return 0;
	return absint(wp_unslash($_GET[$key]));
}

function mpd_render_user_profile_by_url_param() {
	global $wpdb;

	$user_id = mpd_get_int_from_get('user_id');
	if ($user_id <= 0) {
		return '<div class="mpd-profile mpd-error">Invalid user.</div>';
	}

	$users_table = $wpdb->users;
	$usermeta_table = $wpdb->usermeta;

	$user = $wpdb->get_row(
		$wpdb->prepare(
			"SELECT ID, user_login, user_nicename, user_email, user_url, user_registered, display_name
			 FROM {$users_table}
			 WHERE ID = %d
			 LIMIT 1",
			$user_id
		),
		ARRAY_A
	);

	if (!$user) {
		return '<div class="mpd-profile mpd-error">User not found.</div>';
	}

	$meta_keys = array(
		'first_name',
		'last_name',
		'nickname',
		'description',
		'billing_phone',
		'billing_country',
		'billing_state',
		'billing_city',
	);

	$placeholders = implode(',', array_fill(0, count($meta_keys), '%s'));
	$params = $meta_keys;
	array_unshift($params, $user_id);

	$meta_rows = $wpdb->get_results(
		$wpdb->prepare(
			"SELECT meta_key, meta_value
			 FROM {$usermeta_table}
			 WHERE user_id = %d
			   AND meta_key IN ({$placeholders})",
			$params
		),
		ARRAY_A
	);

	$meta = array();
	if ($meta_rows) {
		foreach ($meta_rows as $row) {
			$meta[$row['meta_key']] = maybe_unserialize($row['meta_value']);
		}
	}

	$display_name = $user['display_name'];
	if (empty($display_name)) {
		$display_name = $user['user_login'];
	}

	$first_name = isset($meta['first_name']) ? (string) $meta['first_name'] : '';
	$last_name  = isset($meta['last_name']) ? (string) $meta['last_name'] : '';
	$full_name  = trim($first_name . ' ' . $last_name);

	$profile = array(
		'id'            => (int) $user['ID'],
		'username'      => (string) $user['user_login'],
		'display_name'  => (string) $display_name,
		'full_name'     => (string) $full_name,
		'email'         => (string) $user['user_email'],
		'website'       => (string) $user['user_url'],
		'registered'    => (string) $user['user_registered'],
		'nickname'      => isset($meta['nickname']) ? (string) $meta['nickname'] : '',
		'bio'           => isset($meta['description']) ? (string) $meta['description'] : '',
		'phone'         => isset($meta['billing_phone']) ? (string) $meta['billing_phone'] : '',
		'country'       => isset($meta['billing_country']) ? (string) $meta['billing_country'] : '',
		'state'         => isset($meta['billing_state']) ? (string) $meta['billing_state'] : '',
		'city'          => isset($meta['billing_city']) ? (string) $meta['billing_city'] : '',
	);

	$can_view_email = is_user_logged_in() && (current_user_can('list_users') || get_current_user_id() === $profile['id']);
	if (!$can_view_email) {
		$profile['email'] = '';
	}

	$avatar = get_avatar($profile['id'], 96);

	$out  = '<div class="mpd-profile" data-user-id="' . esc_attr($profile['id']) . '">';
	$out .= '<div class="mpd-profile-header">';
	$out .= '<div class="mpd-avatar">' . $avatar . '</div>';
	$out .= '<div class="mpd-title">';
	$out .= '<h2 class="mpd-name">' . esc_html($profile['display_name']) . '</h2>';
	if ($profile['full_name'] !== '' && $profile['full_name'] !== $profile['display_name']) {
		$out .= '<div class="mpd-full-name">' . esc_html($profile['full_name']) . '</div>';
	}
	$out .= '<div class="mpd-username">@' . esc_html($profile['username']) . '</div>';
	$out .= '</div>';
	$out .= '</div>';

	$out .= '<ul class="mpd-profile-fields">';

	if ($profile['email'] !== '') {
		$out .= '<li><strong>Email:</strong> <a href="mailto:' . esc_attr($profile['email']) . '">' . esc_html($profile['email']) . '</a></li>';
	}

	if ($profile['website'] !== '') {
		$url = esc_url($profile['website']);
		$out .= '<li><strong>Website:</strong> <a href="' . $url . '" rel="nofollow ugc" target="_blank">' . esc_html($url) . '</a></li>';
	}

	if ($profile['phone'] !== '') {
		$out .= '<li><strong>Phone:</strong> ' . esc_html($profile['phone']) . '</li>';
	}

	$location = trim(implode(', ', array_filter(array($profile['city'], $profile['state'], $profile['country']))));
	if ($location !== '') {
		$out .= '<li><strong>Location:</strong> ' . esc_html($location) . '</li>';
	}

	if ($profile['registered'] !== '') {
		$ts = strtotime($profile['registered']);
		$registered = $ts ? date_i18n(get_option('date_format'), $ts) : $profile['registered'];
		$out .= '<li><strong>Member since:</strong> ' . esc_html($registered) . '</li>';
	}

	if ($profile['bio'] !== '') {
		$out .= '<li><strong>Bio:</strong> ' . wp_kses_post(wpautop($profile['bio'])) . '</li>';
	}

	$out .= '</ul>';
	$out .= '</div>';

	return $out;
}

add_shortcode('membership_profile', 'mpd_render_user_profile_by_url_param');